import{_ as a,o as s,c as r,a0 as n}from"./chunks/framework.BJ65gTIr.js";const b=JSON.parse('{"title":"架构概览","description":"Harness-First 工程 —— 模型提供智能，Harness 提供可靠性","frontmatter":{"title":"架构概览","description":"Harness-First 工程 —— 模型提供智能，Harness 提供可靠性"},"headers":[],"relativePath":"zh/architecture/overview.md","filePath":"zh/architecture/overview.md","lastUpdated":1775364101000}'),e={name:"zh/architecture/overview.md"};function d(o,t,l,i,p,h){return s(),r("div",null,[...t[0]||(t[0]=[n(`<h1 id="架构概览" tabindex="-1">架构概览 <a class="header-anchor" href="#架构概览" aria-label="Permalink to &quot;架构概览&quot;">​</a></h1><h2 id="核心原则" tabindex="-1">核心原则 <a class="header-anchor" href="#核心原则" aria-label="Permalink to &quot;核心原则&quot;">​</a></h2><p><strong>Harness-First 工程</strong> — Harness 不是事后考虑，而是基础。</p><p>在快速演进的人工智能辅助软件工程领域，模型所知道的东西与系统所保证的东西之间的区别，已成为定义架构问题的关键。本项目秉持一个根本原则：<strong>模型提供智能，Harness 提供可靠性</strong>。</p><p>这不仅仅是劳动分工——它是一种架构约束，从权限系统保护危险操作到上下文管理最大化有限上下文窗口的利用率，每个设计决策都遵循这一原则。</p><h2 id="五大架构优势" tabindex="-1">五大架构优势 <a class="header-anchor" href="#五大架构优势" aria-label="Permalink to &quot;五大架构优势&quot;">​</a></h2><h3 id="a-harness-first-工程" tabindex="-1">a. Harness-First 工程 <a class="header-anchor" href="#a-harness-first-工程" aria-label="Permalink to &quot;a. Harness-First 工程&quot;">​</a></h3><p>当构建一个与用户具有相同权限的人工智能代理系统时，可靠性不能层层叠加——它必须从第一行代码开始就嵌入其中。</p><p><strong>权限控制</strong>、<strong>超时保护</strong>、<strong>输出截断</strong>和<strong>会话持久化</strong>不是功能——它们是使人工智能代理能够投入生产的安全网。模型可能会产生幻觉、误解指令或选择错误的工具。但 Harness 绝不能在未授权的情况下允许破坏性操作，绝不能无限期挂起，绝不能丢失用户的工作。</p><table tabindex="0"><thead><tr><th>属性</th><th>保证</th></tr></thead><tbody><tr><td>权限控制</td><td>无用户同意或策略批准，破坏性操作不执行</td></tr><tr><td>超时保护</td><td>行为不当的工具（失控的 grep、无限循环）无法挂起会话</td></tr><tr><td>输出截断</td><td>单个工具响应无法消耗整个上下文窗口</td></tr><tr><td>会话持久化</td><td>代理中断后恢复，不丢失对话历史</td></tr></tbody></table><h3 id="b-上下文窗口作为稀缺资源" tabindex="-1">b. 上下文窗口作为稀缺资源 <a class="header-anchor" href="#b-上下文窗口作为稀缺资源" aria-label="Permalink to &quot;b. 上下文窗口作为稀缺资源&quot;">​</a></h3><p>现代大语言模型提供慷慨的上下文窗口，但&quot;慷慨&quot;是一个相对术语，当需要代表整个代码库、多个文件和持续的对话历史时。本架构将上下文视为需要管理的稀缺资源，而不是可以随意挥霍的奢侈品。</p><ul><li><strong>延迟工具加载</strong>：工具注册在中央注册表中；只有工具定义（名称、描述、输入模式）被发送给模型——而非其实现</li><li><strong>250 字符工具描述</strong>：强制在与模型沟通功能时保持严谨</li><li><strong>三级压缩</strong>：消息在达到阈值之前保持完整，然后被压缩成在保留关键信息的同时减少 token 计数的摘要</li></ul><h3 id="c-分层权限防御" tabindex="-1">c. 分层权限防御 <a class="header-anchor" href="#c-分层权限防御" aria-label="Permalink to &quot;c. 分层权限防御&quot;">​</a></h3><p>信任不是二元的，授权也不是。本系统实施了反映现实安全思维的三级权限模型：</p><table tabindex="0"><thead><tr><th>级别</th><th>功能</th><th>使用场景</th></tr></thead><tbody><tr><td><strong>只读</strong></td><td>文件读取、glob 搜索、grep 搜索</td><td>安全探索代码库</td></tr><tr><td><strong>工作区写入</strong></td><td>文件创建、修改、编辑</td><td>受控的开发工作</td></tr><tr><td><strong>危险完全访问</strong></td><td>shell 执行、删除、网络操作</td><td>需要明确批准的全自动化</td></tr></tbody></table><p>权限系统不仅仅检查级别——它根据 <strong>glob 规则匹配</strong> 评估每个操作，以确定是否允许特定路径或操作。策略可能允许编辑 <code>/src/</code> 中的文件，同时阻止修改 <code>/config/</code> 或 <code>/tests/</code>。</p><p><strong>会话记忆</strong>意味着系统记住会话内的批准决策，防止对同一操作重复提示。存在一种<strong>人工在环（Human-in-the-Loop）批准</strong>模式，用于需要在执行前明确确认的操作——对于可能危及系统的破坏性操作或 shell 命令至关重要。</p><h3 id="d-本地优先执行" tabindex="-1">d. 本地优先执行 <a class="header-anchor" href="#d-本地优先执行" aria-label="Permalink to &quot;d. 本地优先执行&quot;">​</a></h3><p>本系统作为纯 Go 二进制文件运行，零运行时依赖。无需配置 Python 环境，无需维护 Node.js 运行时，无需管理虚拟机。代理在主机完整环境中执行，可以访问所有系统资源、环境变量和已安装的工具。</p><p>这种<strong>本地优先</strong>方法消除了虚拟化开销并提供最大性能。代理可以调用开发者日常使用的相同构建工具、linter 和测试运行器。模型的意图与系统的实际能力之间没有抽象层。</p><h3 id="e-mcp-作为通用桥" tabindex="-1">e. MCP 作为通用桥 <a class="header-anchor" href="#e-mcp-作为通用桥" aria-label="Permalink to &quot;e. MCP 作为通用桥&quot;">​</a></h3><p>模型上下文协议（MCP）不是一个封闭的生态系统——它是一个互操作性中心。本系统将 MCP 视为外部工具生态系统的桥梁，使代理能够发现和利用其内置功能之外的能力。</p><p>可以配置 MCP 服务器来提供专门的工具：数据库访问、API 集成、云服务管理或领域特定的分析器。代理以与内置工具相同的方式对待 MCP 工具——具有完全相同的权限执行保证。</p><h2 id="代理循环-状态机" tabindex="-1">代理循环：状态机 <a class="header-anchor" href="#代理循环-状态机" aria-label="Permalink to &quot;代理循环：状态机&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────┐  tool_use  ┌──────────────┐</span></span>
<span class="line"><span>│ REQUEST  │───────────▶│ TOOL_EXEC    │</span></span>
<span class="line"><span>│          │◀───────────│              │</span></span>
<span class="line"><span>└────┬─────┘  result    └──────┬───────┘</span></span>
<span class="line"><span>     │                         │</span></span>
<span class="line"><span>end_turn│                 error│</span></span>
<span class="line"><span>     ▼                         ▼</span></span>
<span class="line"><span>┌──────────┐           ┌──────────────┐</span></span>
<span class="line"><span>│ TERMINATE│           │ CONTINUE     │</span></span>
<span class="line"><span>└──────────┘           └──────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><table tabindex="0"><thead><tr><th>状态</th><th>转换</th><th>条件</th></tr></thead><tbody><tr><td>REQUEST</td><td>→ TOOL_EXEC</td><td>模型调用工具 (tool_use)</td></tr><tr><td>REQUEST</td><td>→ TERMINATE</td><td>任务完成 (end_turn)</td></tr><tr><td>TOOL_EXEC</td><td>→ CONTINUE</td><td>工具成功，继续循环</td></tr><tr><td>TOOL_EXEC</td><td>→ CONTINUE</td><td>工具失败但可恢复</td></tr><tr><td>TOOL_EXEC</td><td>→ TERMINATE</td><td>不可恢复的失败</td></tr></tbody></table><h2 id="设计决策" tabindex="-1">设计决策 <a class="header-anchor" href="#设计决策" aria-label="Permalink to &quot;设计决策&quot;">​</a></h2><table tabindex="0"><thead><tr><th>决策</th><th>理由</th><th>权衡</th></tr></thead><tbody><tr><td><strong>Go 实现</strong></td><td>静态链接、单二进制部署、可预测的内存使用</td><td>不如解释型语言灵活</td></tr><tr><td><strong>三级权限</strong></td><td>二进制允许/拒绝对于不同的开发工作流程是不够的</td><td>配置更复杂，但支持实际使用</td></tr><tr><td><strong>Glob 规则匹配</strong></td><td>允许对哪些文件可以被修改进行细粒度控制</td><td>需要用户理解 glob 模式</td></tr><tr><td><strong>250 字符工具描述</strong></td><td>强制能力沟通的纪律；防止上下文膨胀</td><td>可能遗漏有用的工具细节</td></tr><tr><td><strong>MAX_TURNS = 50</strong></td><td>防止无限循环导致的资源耗尽</td><td>复杂任务可能需要更多迭代</td></tr><tr><td><strong>三级消息压缩</strong></td><td>在管理 token 限制的同时保留语义内容</td><td>压缩是有损的；某些上下文可能丢失</td></tr><tr><td><strong>MCP 作为外部适配器</strong></td><td>协议无关的工具发现；生态系统集成</td><td>MCP 服务器添加外部依赖</td></tr></tbody></table><h2 id="目标读者" tabindex="-1">目标读者 <a class="header-anchor" href="#目标读者" aria-label="Permalink to &quot;目标读者&quot;">​</a></h2><p>本文档面向：</p><ul><li><strong>人工智能代理架构研究者</strong> — 研究 Harness 设计如何影响代理能力</li><li><strong>评估生产系统 Harness-First 工程模式的高级工程师</strong></li><li><strong>寻求生产级人工智能工具参考实现的技术负责人</strong></li></ul><p>贯穿始终的重点是 <em>为什么</em> 而不是 <em>是什么</em> — 代码揭示实现细节，但这些页面解释的是其背后的 reasoning。</p><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="./design-philosophy.html">设计理念</a> — 深入探讨智能/可靠性分离</li><li><a href="./agent-loop.html">Agent Loop</a> — 状态机机制和历史管理</li><li><a href="./tools.html">工具系统</a> — 内置工具和扩展机制</li><li><a href="./../guide/configuration.html">配置指南</a> — 权限策略和模型设置</li></ul>`,35)])])}const g=a(e,[["render",d]]);export{b as __pageData,g as default};
